const audioDataUrl = "data:audio/wav;base64,"

export default function Test() {
  const [url, setUrl] = useState<string>('');

  const {
    isRendering,
    progress,
    status,
    error,
    startRender,
  } = useRemotionRender();

  const handleRender = async () => {
    const resultClean = results.map((res, idx) => ({
      index: idx,
      segment: res.segment,
      videoUrl: res.videoUrl || null,
      seed: res.seed || Math.floor(Math.random() * 10000),
      failed: res.failed,
      duration: res.segment.end - res.segment.start,
    }));

    startRender(resultClean, audioDataUrl, setUrl);
  };

  return (
    <>
      <button disabled={isRendering} onClick={handleRender}>
        {isRendering ? 'Rendering...' : 'Start Render'}
      </button>

      {status && (
        <div>
          <p>Status: {status.stage}</p>
          {status.stage === 'rendering' && <progress value={progress} max={100} />}
          <p>{progress}%</p>
        </div>
      )}

      {url && <video src={url} controls />}
      {error && <p style={{ color: 'red' }}>Error: {error}</p>}
    </>
  )
}